import React, { useRef, useState } from 'react';
import GanttBar from './GanttBar';
import EventBar from './EventBar';

// ── Layout constants ──────────────────────────────────────────────────────────
const LEFT_WIDTH = 260;
const DAY_WIDTH = 38;
const ROW_HEIGHT = 48;
const SQUAD_HEIGHT = 36;
const HEADER_HEIGHT = 56;
const BAR_PADDING = 6;

// ── Squad color palette ───────────────────────────────────────────────────────
const SQUAD_COLORS = [
  { bg: '#E3FCEF', border: '#00875A', text: '#006644' },
  { bg: '#DEEBFF', border: '#0052CC', text: '#0747A6' },
  { bg: '#EAE6FF', border: '#5243AA', text: '#403294' },
  { bg: '#FFEBE6', border: '#BF2600', text: '#BF2600' },
  { bg: '#FFF0B3', border: '#FF8B00', text: '#FF8B00' },
  { bg: '#E6FCFF', border: '#00B8D9', text: '#006887' },
  { bg: '#FFEDF5', border: '#CD519D', text: '#943D73' },
];

function squadColor(squadName) {
  let hash = 0;
  for (let i = 0; i < squadName.length; i++) {
    hash = (hash * 31 + squadName.charCodeAt(i)) & 0xffffffff;
  }
  return SQUAD_COLORS[Math.abs(hash) % SQUAD_COLORS.length];
}

// ── Group items (Jira issues + custom events) into Squad → Developer ──────────
function groupItems(issues, customEvents) {
  const squads = {};

  for (const issue of issues) {
    const { fields } = issue;
    const squad = (fields.labels && fields.labels[0]) || 'No Squad';
    const dev = fields.assignee ? fields.assignee.displayName : 'Unassigned';

    if (!squads[squad]) squads[squad] = {};
    if (!squads[squad][dev]) squads[squad][dev] = [];
    squads[squad][dev].push({ ...issue, _type: 'jira' });
  }

  for (const evt of customEvents) {
    const squad = evt.squad || 'No Squad';
    const dev = evt.developer || 'Unassigned';

    if (!squads[squad]) squads[squad] = {};
    if (!squads[squad][dev]) squads[squad][dev] = [];
    squads[squad][dev].push({ ...evt, _type: 'custom' });
  }

  return squads;
}

// ── Date helpers ──────────────────────────────────────────────────────────────
function addDays(date, n) {
  const d = new Date(date);
  d.setDate(d.getDate() + n);
  return d;
}

function daysBetween(a, b) {
  return Math.round((b - a) / 86400000);
}

function fmtDateShort(date) {
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return `${months[date.getMonth()]} ${date.getDate()}`;
}

// ── Main component ────────────────────────────────────────────────────────────
export default function GanttChart({ issues, customEvents, viewYear, viewMonth, today, onEditEvent, onDeleteEvent }) {
  const scrollRef = useRef(null);
  const [collapsedSquads, setCollapsedSquads] = useState(new Set());

  const viewStart = new Date(viewYear, viewMonth, 1);
  const viewEnd = new Date(viewYear, viewMonth + 1, 0);
  const totalDays = daysBetween(viewStart, viewEnd) + 1;
  const totalWidth = totalDays * DAY_WIDTH;
  const todayOffset = daysBetween(viewStart, today) * DAY_WIDTH;

  const grouped = groupItems(issues, customEvents || []);
  const squadNames = Object.keys(grouped).sort();

  const rows = [];
  for (const squad of squadNames) {
    const color = squadColor(squad);
    rows.push({ type: 'squad', squad, color });
    if (!collapsedSquads.has(squad)) {
      const devs = Object.keys(grouped[squad]).sort();
      for (const dev of devs) {
        rows.push({ type: 'dev', squad, dev, color, items: grouped[squad][dev] });
      }
    }
  }

  function toggleSquad(squad) {
    setCollapsedSquads((prev) => {
      const next = new Set(prev);
      next.has(squad) ? next.delete(squad) : next.add(squad);
      return next;
    });
  }

  // ── Header ────────────────────────────────────────────────────────────────
  function renderHeader() {
    const dayEls = [];
    const weekEls = [];
    let weekStart = 0;
    let weekLabel = '';

    for (let i = 0; i < totalDays; i++) {
      const d = addDays(viewStart, i);
      const isToday = daysBetween(today, d) === 0;
      const isWeekend = d.getDay() === 0 || d.getDay() === 6;
      const dayName = ['Su','Mo','Tu','We','Th','Fr','Sa'][d.getDay()];

      if (d.getDay() === 0 || i === 0) {
        if (i > 0) {
          weekEls.push(
            <div key={`week-${weekStart}`} style={{ ...styles.weekLabel, left: weekStart * DAY_WIDTH, width: (i - weekStart) * DAY_WIDTH }}>
              {weekLabel}
            </div>
          );
        }
        weekStart = i;
        weekLabel = fmtDateShort(d);
      }

      dayEls.push(
        <div
          key={i}
          style={{
            ...styles.dayCell,
            left: i * DAY_WIDTH,
            background: isToday ? '#DEEBFF' : isWeekend ? '#F4F5F7' : '#fff',
            fontWeight: isToday ? 700 : 400,
            color: isToday ? '#0052CC' : isWeekend ? '#97A0AF' : '#42526E',
          }}
        >
          <div style={styles.dayName}>{dayName}</div>
          <div style={styles.dayNum}>{d.getDate()}</div>
        </div>
      );
    }

    weekEls.push(
      <div key={`week-${weekStart}`} style={{ ...styles.weekLabel, left: weekStart * DAY_WIDTH, width: (totalDays - weekStart) * DAY_WIDTH }}>
        {weekLabel}
      </div>
    );

    return (
      <div style={{ ...styles.headerRight, width: totalWidth }}>
        <div style={{ position: 'relative', height: 22 }}>{weekEls}</div>
        <div style={{ position: 'relative', height: 34 }}>{dayEls}</div>
      </div>
    );
  }

  // ── Weekend shading ───────────────────────────────────────────────────────
  function renderWeekendShading() {
    const shades = [];
    for (let i = 0; i < totalDays; i++) {
      const d = addDays(viewStart, i);
      if (d.getDay() === 0 || d.getDay() === 6) {
        shades.push(
          <div key={i} style={{ position: 'absolute', left: i * DAY_WIDTH, top: 0, width: DAY_WIDTH, height: '100%', background: '#F4F5F7', pointerEvents: 'none' }} />
        );
      }
    }
    return shades;
  }

  // ── Empty state ───────────────────────────────────────────────────────────
  const totalItems = issues.length + (customEvents || []).length;
  if (totalItems === 0) {
    return (
      <div style={styles.emptyState}>
        <div style={{ fontSize: '48px' }}>📋</div>
        <div style={{ fontWeight: 600, fontSize: '16px', color: '#172B4D' }}>No issues found</div>
        <div style={{ color: '#6B778C', fontSize: '13px' }}>
          Try adjusting the projects, date range, or status filter.
        </div>
      </div>
    );
  }

  // ── Render bars for a dev row ─────────────────────────────────────────────
  function renderBars(items, color) {
    return items.map((item, i) => {
      if (item._type === 'custom') {
        return (
          <EventBar
            key={item.id || `evt-${i}`}
            event={item}
            viewStart={viewStart}
            dayWidth={DAY_WIDTH}
            rowHeight={ROW_HEIGHT}
            barPadding={BAR_PADDING}
            totalDays={totalDays}
            onEdit={onEditEvent}
            onDelete={onDeleteEvent}
          />
        );
      }
      return (
        <GanttBar
          key={item.key}
          issue={item}
          viewStart={viewStart}
          dayWidth={DAY_WIDTH}
          rowHeight={ROW_HEIGHT}
          barPadding={BAR_PADDING}
          totalDays={totalDays}
          squadColor={color}
        />
      );
    });
  }

  return (
    <div style={styles.outer}>
      {/* ── Fixed left panel header ── */}
      <div style={styles.leftHeader}>
        <span style={{ fontWeight: 600, fontSize: '12px', color: '#6B778C' }}>SQUAD / DEVELOPER</span>
        <span style={{ fontSize: '11px', color: '#97A0AF' }}>
          {issues.length} issue{issues.length !== 1 ? 's' : ''}
          {(customEvents || []).length > 0 ? ` · ${customEvents.length} event${customEvents.length !== 1 ? 's' : ''}` : ''}
        </span>
      </div>

      {/* ── Timeline header (scrollable, synced) ── */}
      <div
        style={{ position: 'absolute', left: LEFT_WIDTH, top: 0, right: 0, height: HEADER_HEIGHT, overflowX: 'hidden', background: '#fff', borderBottom: '2px solid #DFE1E6', zIndex: 10 }}
        id="gantt-header-scroll"
      >
        {renderHeader()}
      </div>

      {/* ── Scrollable body ── */}
      <div
        style={{ position: 'absolute', left: 0, top: HEADER_HEIGHT, right: 0, bottom: 0, overflowY: 'auto', overflowX: 'auto' }}
        ref={scrollRef}
        onScroll={(e) => {
          const header = document.getElementById('gantt-header-scroll');
          if (header) header.scrollLeft = e.currentTarget.scrollLeft;
        }}
      >
        <div style={{ display: 'flex', minWidth: LEFT_WIDTH + totalWidth }}>
          {/* Sticky left column */}
          <div style={{ width: LEFT_WIDTH, flexShrink: 0, position: 'sticky', left: 0, zIndex: 5, background: '#fff', borderRight: '2px solid #DFE1E6' }}>
            {rows.map((row, idx) => {
              if (row.type === 'squad') {
                const isCollapsed = collapsedSquads.has(row.squad);
                return (
                  <div
                    key={`left-squad-${row.squad}`}
                    style={{ ...styles.squadLabel, background: row.color.bg, borderLeft: `4px solid ${row.color.border}`, color: row.color.text, height: SQUAD_HEIGHT }}
                    onClick={() => toggleSquad(row.squad)}
                  >
                    <span style={styles.collapseIcon}>{isCollapsed ? '▶' : '▼'}</span>
                    <span style={styles.squadName}>{row.squad}</span>
                    <span style={styles.issueCount}>{Object.values(grouped[row.squad]).flat().length}</span>
                  </div>
                );
              }
              const isEven = idx % 2 === 0;
              return (
                <div
                  key={`left-dev-${row.squad}-${row.dev}`}
                  style={{ ...styles.devLabel, height: ROW_HEIGHT, background: isEven ? '#fff' : '#FAFBFC', borderLeft: `4px solid ${row.color.border}` }}
                >
                  <div style={styles.devAvatar}>{row.dev.split(' ').map((n) => n[0]).join('').slice(0, 2).toUpperCase()}</div>
                  <span style={styles.devName} title={row.dev}>{row.dev}</span>
                  <span style={styles.devCount}>{row.items.length}</span>
                </div>
              );
            })}
          </div>

          {/* Timeline body */}
          <div style={{ width: totalWidth, flexShrink: 0, position: 'relative' }}>
            {rows.map((row, idx) => {
              if (row.type === 'squad') {
                return (
                  <div key={`right-squad-${row.squad}`} style={{ height: SQUAD_HEIGHT, background: row.color.bg, borderBottom: `1px solid ${row.color.border}33`, opacity: 0.6 }} />
                );
              }
              const isEven = idx % 2 === 0;
              return (
                <div
                  key={`right-dev-${row.squad}-${row.dev}`}
                  style={{ position: 'relative', height: ROW_HEIGHT, background: isEven ? '#fff' : '#FAFBFC', borderBottom: '1px solid #F4F5F7' }}
                >
                  {renderWeekendShading()}
                  {todayOffset >= 0 && todayOffset <= totalWidth && (
                    <div style={{ ...styles.todayLine, left: todayOffset }} />
                  )}
                  {renderBars(row.items, row.color)}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  outer: { position: 'relative', flex: 1, overflow: 'hidden', background: '#fff' },
  leftHeader: {
    position: 'absolute', left: 0, top: 0, width: LEFT_WIDTH, height: HEADER_HEIGHT,
    background: '#fff', borderRight: '2px solid #DFE1E6', borderBottom: '2px solid #DFE1E6',
    zIndex: 11, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 12px',
  },
  headerRight: { position: 'relative', height: HEADER_HEIGHT },
  weekLabel: {
    position: 'absolute', top: 0, height: 22, display: 'flex', alignItems: 'center',
    paddingLeft: '6px', fontSize: '10px', fontWeight: 600, color: '#6B778C',
    textTransform: 'uppercase', letterSpacing: '0.5px', borderRight: '1px solid #EBECF0', boxSizing: 'border-box',
  },
  dayCell: {
    position: 'absolute', top: 0, width: DAY_WIDTH, height: 34,
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
    borderRight: '1px solid #EBECF0', boxSizing: 'border-box', fontSize: '11px',
  },
  dayName: { fontSize: '10px', opacity: 0.7 },
  dayNum: { fontWeight: 600, fontSize: '12px' },
  squadLabel: {
    display: 'flex', alignItems: 'center', gap: '6px', padding: '0 10px',
    cursor: 'pointer', borderBottom: '1px solid rgba(0,0,0,0.06)', userSelect: 'none', overflow: 'hidden',
  },
  collapseIcon: { fontSize: '9px', opacity: 0.7, flexShrink: 0 },
  squadName: { fontWeight: 700, fontSize: '12px', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' },
  issueCount: { fontSize: '11px', opacity: 0.6, flexShrink: 0 },
  devLabel: { display: 'flex', alignItems: 'center', gap: '8px', padding: '0 10px', borderBottom: '1px solid #F4F5F7', overflow: 'hidden' },
  devAvatar: {
    width: 26, height: 26, borderRadius: '50%', background: '#DFE1E6', color: '#42526E',
    display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '10px', fontWeight: 700, flexShrink: 0,
  },
  devName: { flex: 1, fontSize: '12px', fontWeight: 500, color: '#172B4D', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' },
  devCount: { fontSize: '11px', color: '#97A0AF', flexShrink: 0 },
  todayLine: { position: 'absolute', top: 0, bottom: 0, width: 2, background: '#0052CC', zIndex: 3, pointerEvents: 'none' },
  emptyState: { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '12px', color: '#6B778C' },
};
